const fs = require('fs/promises');
const path = require('path');

async function directoryOps() {
  // Create nested directories recursively
  await fs.mkdir('demo/src/utils', { recursive: true });
  console.log('Directories created');

  // Create some files
  await fs.writeFile('demo/src/index.js', 'console.log("hi")');
  await fs.writeFile('demo/src/utils/helpers.js', '// helpers');
  await fs.writeFile('demo/README.md', '# Demo');

  // List directory contents (simple)
  const files = await fs.readdir('demo');
  console.log('demo/:', files);

  // List with file type info
  const entries = await fs.readdir('demo', { withFileTypes: true });
  entries.forEach(entry => {
    const type = entry.isDirectory() ? 'DIR' : 'FILE';
    console.log(`  ${type}: ${entry.name}`);
  });

  // Recursive listing (Node 18.17+)
  const allFiles = await fs.readdir('demo', { recursive: true });
  console.log('\nAll files:', allFiles);

  // Clean up
  await fs.rm('demo', { recursive: true });
  console.log('Cleaned up');
}

directoryOps();

const fs = require('fs/promises');

async function fileInfo() {
  // Create a test file
  await fs.writeFile('test.txt', 'Hello, World!');

  const stats = await fs.stat('test.txt');

  console.log('Is file:', stats.isFile());
  console.log('Is directory:', stats.isDirectory());
  console.log('Size:', stats.size, 'bytes');
  console.log('Created:', stats.birthtime.toISOString());
  console.log('Modified:', stats.mtime.toISOString());
  console.log('Accessed:', stats.atime.toISOString());

  // Check if file exists (modern approach)
  try {
    await fs.access('test.txt');
    console.log('\nFile exists');
  } catch {
    console.log('\nFile does not exist');
  }

  // Clean up
  await fs.unlink('test.txt');
  console.log('File deleted');
}

fileInfo();

