const fs = require('fs/promises');

async function reportSizes() {
  await fs.writeFile('a.txt', 'Hello');
  await fs.writeFile('b.txt', 'Hello World');
  await fs.writeFile('c.txt', 'Hi');

  for (const file of ['a.txt', 'b.txt', 'c.txt']) {
    const stats = await fs.stat(file);
    console.log(`${file}: ${stats.size} bytes`);
  }

  await fs.unlink('a.txt');
  await fs.unlink('b.txt');
  await fs.unlink('c.txt');
}

reportSizes();
